package bead

import (
	"fmt"
	"math"
	"sort"
	"sync"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
)

func TestPerformance_BeadStoreConcurrentClaimReadyHeartbeatUnderBudget(t *testing.T) {
	skipFullBeadSuiteInShort(t)
	s := newTestStore(t)

	// Seed a small, deterministic open-bead corpus. The IDs, timestamps, and
	// titles are fixed so the test exercises the same JSONL shape every run.
	const corpusSize = 8
	corpus := make([]Bead, 0, corpusSize)
	baseTime := time.Unix(1_700_000_000, 0).UTC()
	for i := 0; i < corpusSize; i++ {
		corpus = append(corpus, Bead{
			ID:        fmt.Sprintf("ddx-perf-%02d", i),
			Title:     fmt.Sprintf("perf bead %02d", i),
			IssueType: DefaultType,
			Status:    StatusOpen,
			Priority:  i % 3,
			CreatedAt: baseTime.Add(time.Duration(i) * time.Second),
			UpdatedAt: baseTime.Add(time.Duration(i) * time.Second),
		})
	}
	require.NoError(t, s.WriteAll(corpus))

	var (
		mu      sync.Mutex
		samples []LockSample
	)
	prevSink := LockMetricsSink
	LockMetricsSink = func(sample LockSample) {
		mu.Lock()
		samples = append(samples, sample)
		mu.Unlock()
	}
	t.Cleanup(func() {
		LockMetricsSink = prevSink
	})

	const (
		workerCount = 4
		rounds      = 8
	)

	start := make(chan struct{})
	var wg sync.WaitGroup
	errCh := make(chan error, workerCount+1)

	// Writer workers each own a bead so the workload remains deterministic
	// while still contending on the store-wide lock.
	for worker := 0; worker < workerCount; worker++ {
		worker := worker
		beadID := corpus[worker].ID
		wg.Add(1)
		go func() {
			defer wg.Done()
			<-start
			owner := fmt.Sprintf("perf-worker-%d", worker)
			for round := 0; round < rounds; round++ {
				if err := s.Claim(beadID, owner); err != nil {
					errCh <- fmt.Errorf("worker %d claim round %d: %w", worker, round, err)
					return
				}
				if err := s.Heartbeat(beadID); err != nil {
					errCh <- fmt.Errorf("worker %d heartbeat round %d: %w", worker, round, err)
					return
				}
				if err := s.AppendEvent(beadID, BeadEvent{
					Kind:    "performance",
					Summary: fmt.Sprintf("worker=%d round=%d", worker, round),
				}); err != nil {
					errCh <- fmt.Errorf("worker %d append round %d: %w", worker, round, err)
					return
				}
				if err := s.Release(beadID, owner, StatusOpen); err != nil {
					errCh <- fmt.Errorf("worker %d release round %d: %w", worker, round, err)
					return
				}
			}
		}()
	}

	// ReadyExecution is read-only, so run it in parallel to keep the open-bead
	// corpus under mixed claim/read pressure while the writer goroutines churn.
	wg.Add(1)
	go func() {
		defer wg.Done()
		<-start
		for i := 0; i < rounds*workerCount; i++ {
			_, err := s.ReadyExecution()
			if err != nil {
				errCh <- fmt.Errorf("ready execution iteration %d: %w", i, err)
				return
			}
		}
	}()

	close(start)
	wg.Wait()
	close(errCh)

	for err := range errCh {
		require.NoError(t, err)
	}

	finalReady, err := s.ReadyExecution()
	require.NoError(t, err)
	require.Len(t, finalReady, corpusSize)

	mu.Lock()
	got := append([]LockSample(nil), samples...)
	mu.Unlock()

	require.GreaterOrEqual(t, len(got), workerCount*rounds*4,
		"expected lock samples from claim/heartbeat/event/release cycles")

	waitSamples := make([]float64, 0, len(got))
	holdSamples := make([]float64, 0, len(got))
	for _, sample := range got {
		waitSamples = append(waitSamples, float64(sample.Wait)/float64(time.Millisecond))
		holdSamples = append(holdSamples, float64(sample.Hold)/float64(time.Millisecond))
	}

	p95Wait := percentileFloat(waitSamples, 0.95)
	p99Wait := percentileFloat(waitSamples, 0.99)
	p95Hold := percentileFloat(holdSamples, 0.95)
	p99Hold := percentileFloat(holdSamples, 0.99)

	require.NotEmpty(t, got, "expected lock samples from claim/heartbeat/event/release cycles")

	const (
		maxP95WaitMS = 25.0
		// Leave headroom for shared builders and concurrent package execution;
		// the p95 budgets still catch the steady-state path.
		maxP99WaitMS = 1500.0
		maxP95HoldMS = 50.0
		maxP99HoldMS = 200.0
	)

	require.Less(t, p95Wait, maxP95WaitMS,
		"p95 lock wait %.2fms exceeded budget %.2fms", p95Wait, maxP95WaitMS)
	require.Less(t, p99Wait, maxP99WaitMS,
		"p99 lock wait %.2fms exceeded budget %.2fms", p99Wait, maxP99WaitMS)
	require.Less(t, p95Hold, maxP95HoldMS,
		"p95 lock hold %.2fms exceeded budget %.2fms", p95Hold, maxP95HoldMS)
	require.Less(t, p99Hold, maxP99HoldMS,
		"p99 lock hold %.2fms exceeded budget %.2fms", p99Hold, maxP99HoldMS)
}

func percentileFloat(values []float64, p float64) float64 {
	if len(values) == 0 {
		return 0
	}
	cp := append([]float64(nil), values...)
	sort.Float64s(cp)
	if p <= 0 {
		return cp[0]
	}
	if p >= 1 {
		return cp[len(cp)-1]
	}
	rank := int(math.Ceil(p*float64(len(cp)))) - 1
	if rank < 0 {
		rank = 0
	}
	if rank >= len(cp) {
		rank = len(cp) - 1
	}
	return cp[rank]
}

package bead

import (
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"
)

// StaleLockAge is the duration after which a lock is considered stale
// and can be forcibly broken. Default: 2 hours.
var StaleLockAge = 2 * time.Hour

// LockSample carries timing metrics for one Store.WithLock acquire/release cycle.
type LockSample struct {
	LockDir string
	Wait    time.Duration // time from WithLock entry to lock acquisition
	Hold    time.Duration // time the callback held the lock
}

// LockMetricsSink is called after each successful Store.WithLock acquire+release
// cycle. The zero value (nil) is a no-op. Tests may swap this to capture metrics.
var LockMetricsSink func(LockSample)

// WithLock acquires the file lock, runs fn, then releases the lock.
// For external backends, locking is delegated to the backend tool.
func (s *Store) WithLock(fn func() error) error {
	if s.backend != nil {
		return s.backend.WithLock(fn)
	}
	waitStart := time.Now()
	if err := s.acquireLock(); err != nil {
		return err
	}
	waitDur := time.Since(waitStart)
	holdStart := time.Now()
	defer s.releaseLock()
	fnErr := fn()
	if sink := LockMetricsSink; sink != nil {
		sink(LockSample{LockDir: s.LockDir, Wait: waitDur, Hold: time.Since(holdStart)})
	}
	return fnErr
}

func (s *Store) acquireLock() error {
	return acquireDirLock(s.Dir, s.LockDir, s.LockWait)
}

// acquireDirLock is the file-lock primitive used by both Store and the
// standalone JSONLBackend. dir is the directory to ensure exists before the
// lock is taken; lockDir is the lock directory itself; wait bounds the spin.
func acquireDirLock(dir, lockDir string, wait time.Duration) error {
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: lock dir: %w", err)
	}

	deadline := time.Now().Add(wait)
	for {
		err := os.Mkdir(lockDir, 0o755)
		if err == nil {
			_ = os.WriteFile(filepath.Join(lockDir, "pid"),
				[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
			_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
				[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
			return nil
		}

		if breakStaleLockDir(lockDir) {
			continue
		}

		if time.Now().After(deadline) {
			owner := "unknown"
			pidData, _ := os.ReadFile(filepath.Join(lockDir, "pid"))
			if len(pidData) > 0 {
				owner = strings.TrimSpace(string(pidData))
			}
			return fmt.Errorf("bead: lock timeout (owner pid: %s)", owner)
		}
		time.Sleep(50 * time.Millisecond)
	}
}

// breakStaleLockDir checks if the existing lock is stale (owner dead or too
// old) and breaks it if so. Returns true if lock was broken.
func breakStaleLockDir(lockDir string) bool {
	pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
	if err == nil {
		pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
		if err == nil && pid > 0 && pid != os.Getpid() {
			if !processAlive(pid) {
				os.RemoveAll(lockDir)
				return true
			}
		}
	}

	acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
	if err == nil {
		acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
		if err == nil && time.Since(acquired) > StaleLockAge {
			os.RemoveAll(lockDir)
			return true
		}
	}

	return false
}

func (s *Store) releaseLock() {
	os.RemoveAll(s.LockDir)
}

package bead

import (
	"fmt"
	"os"
	"path/filepath"
	"sync"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
)

// TestWithLock_RecordsWaitDuration asserts that LockMetricsSink is called with
// a measurable wait duration when WithLock must spin waiting for a contended lock.
func TestWithLock_RecordsWaitDuration(t *testing.T) {
	var mu sync.Mutex
	var captured []LockSample
	prev := LockMetricsSink
	LockMetricsSink = func(s LockSample) {
		mu.Lock()
		captured = append(captured, s)
		mu.Unlock()
	}
	defer func() { LockMetricsSink = prev }()

	s := newTestStore(t)

	// Pre-acquire the lock with the current PID so breakStaleLockDir cannot reclaim it.
	require.NoError(t, os.MkdirAll(s.LockDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(s.LockDir, "pid"),
		[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(s.LockDir, "acquired_at"),
		[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644))

	// Release the lock after 20ms so WithLock experiences measurable contention.
	go func() {
		time.Sleep(20 * time.Millisecond)
		os.RemoveAll(s.LockDir)
	}()

	err := s.WithLock(func() error { return nil })
	require.NoError(t, err)

	mu.Lock()
	got := append([]LockSample(nil), captured...)
	mu.Unlock()

	if len(got) == 0 {
		t.Fatal("LockMetricsSink was not called")
	}
	if got[0].LockDir != s.LockDir {
		t.Fatalf("LockSample.LockDir = %q, want %q", got[0].LockDir, s.LockDir)
	}
	if got[0].Wait < 5*time.Millisecond {
		t.Fatalf("expected wait >= 5ms for contended lock, got %v", got[0].Wait)
	}
}
